selector_to_html = {"a[href=\"Interface/control_mod/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1 </span>Control Module<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Control Module \u2013 Providing a Complete Low-Level Robot Control Interface</strong></p><p>The control module is a core component of the AgiBot X2 AimDK, providing comprehensive low-level control interfaces for the robot. It follows the ROS2 standard and supports both C++ and Python, enabling developers to achieve flexible and efficient robot control.</p>", "a[href=\"about_agibot_X2/onboard_computer.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.3 </span>On-board Computer<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>The AgiBot X2 Ultra comes standard with a motion control computing unit, an interaction computing unit, and a developer computing unit, providing stronger computational power and greater flexibility for complex tasks and advanced applications.</p>", "a[href=\"about_agibot_X2/SDK_interface.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.5 </span>Secondary Development Interfaces (Ultra Edition)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"quick_start/prerequisites.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.1 </span>Read the user guide to familiarize yourself with relevant terminology and safety precautions.<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"Interface/hal/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.4 </span>Hardware Abstraction Module<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Hardware Abstraction Module \u2013 Provides Low-Level Hardware Interfaces and Sensor Data Access</strong></p><p>The hardware abstraction module is a foundational component of the AgiBot X2 AimDK, providing abstracted interfaces to the robot\u2019s various hardware devices. It follows the ROS2 standard and supports both C++ and Python, offering developers a unified hardware access interface.</p>", "a[href=\"quick_start/code_sample.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6 </span>Code Implementation<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>In this section, you will develop a simple robot control program that makes robot X2 perform a sequence of hand motions and speech playback.</strong></p>", "a[href=\"faq/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">7 </span><i class=\"fa-regular fa-circle-question\"></i> FAQ<a class=\"headerlink\" href=\"#faq\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>Q: Running the example reports: \u201cPackage \u2018examples\u2019 not found\u201d</strong></p>", "a[href=\"operation_guide/remote_controller.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.3 </span>Remote Controller Connection<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">2.3.1 </span>Operation Steps<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>1. Open the \u201cAdd Robot\u201d page</strong></p>", "a[href=\"quick_start/run_example.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.5 </span>Run an Example Program<a class=\"headerlink\" href=\"#aimdk-run\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">4.5.1 </span>Get the Robot\u2019s Current State<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Sample Output</strong></p><p>If you see the following output, you have successfully connected to the robot and retrieved its current Locomotion Mode.</p>", "a[href=\"Interface/perception/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.5 </span>Perception Module (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 SDK Perception Module \u2013 Provides multi-modal perception capabilities</strong></p><p>Key Features</p>", "a[href=\"end_notes.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9 </span><i class=\"fa fa-triangle-exclamation\"></i> Boundaries &amp; Disclaimer for Secondary Development<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"about_agibot_X2/user_debug_interface.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4 </span>User Debug Interfaces (Ultra Edition)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"faq/temp_works.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8 </span><i class=\"fa fa-gears\"></i> Temporary Transitional Solutions Statement<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">8.1 </span>Disable the Built-in Interaction System and Use Your Own Voice System<a class=\"headerlink\" href=\"#agent-only-voice\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>By default, when the robot is powered on, it automatically enters natural voice interaction mode, and the interaction module occupies the audio input/output streams.</strong> If you need to integrate your own voice system and access the audio streams, you can temporarily disable the built-in interaction module using the steps below. <strong>Future versions will support one-click switching to secondary-development interaction mode to further simplify custom voice system integration.</strong></p>", "a[href=\"operation_guide/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2 </span><i class=\"fa-regular fa-map\"></i> Operation Guide<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"get_sdk/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3 </span><i class=\"fa fa-cloud-arrow-down\"></i> Get the SDK<a class=\"headerlink\" href=\"#sdk\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"example/Cpp.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2 </span>C++ Interface Usage Example<a class=\"headerlink\" href=\"#c\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This section will guide you through implementing the functions listed in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"Interface/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5 </span><i class=\"fa fa-plug\"></i> Interface Description<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Interface Documentation \u2013 ROS2-based humanoid robot development interfaces</strong></p><p>The AgiBot X2 AimDK provides a complete set of ROS2 interfaces for controlling the AgiBot X2 humanoid robot. The interfaces follow ROS2 standards and support both C++ and Python, offering developers a flexible and efficient environment for robot application development.</p>", "a[href=\"operation_guide/start_up_guide.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1 </span>Startup Guide<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">2.1.1 </span>Startup While Suspended (Gantry Required) (Recommended for SDK use)<a class=\"headerlink\" href=\"#sdk\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Step 1: Unbox and Position Properly</strong> Open the package as shown and carefully lift the robot out. Use the support frame to suspend the robot naturally, ensuring that the feet do not touch the ground.</p>", "a[href=\"operation_guide/robot_connection.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.2 </span>Robot Mobile App Connection (Agibot Go APP)<a class=\"headerlink\" href=\"#app-agibot-go-app\" title=\"Link to this heading\">\uf0c1</a></h1><p>The latest app version must match the robot\u2019s latest firmware version. Please download the correct version.</p>", "a[href=\"example/Python.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1 </span>Python interface usage example<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This chapter will guide you through implementing several features shown in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"quick_start/prerequisites.html#aimdk-build\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.4 </span>Environment installation and configuration<a class=\"headerlink\" href=\"#aimdk-build\" title=\"Link to this heading\">\uf0c1</a></h1><p>Place the SDK into the target environment and extract it.</p>", "a[href=\"example/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6 </span><i class=\"fa fa-code\"></i> Example Code<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"#aimdk-x2\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Introduction to AimDK_X2<a class=\"headerlink\" href=\"#aimdk-x2\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AimDK_X2</strong> is a task-level programming and extension framework developed by <strong>AgiBot Robotics</strong>, designed to provide <strong>secondary developers</strong> with open interfaces and supporting tools for the AgiBot X2 humanoid robot. With AimDK, developers can easily interact with the robot system, control robot behaviors, access sensor data, and build customized applications and intelligent functions.</p><p><strong>Design Goals</strong></p>", "a[href=\"about_agibot_X2/coordinate_system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.8 </span>Coordinate System<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>When all joint angles are at their zero positions, the coordinate systems of each robot component are distributed as shown in the figure below. <strong>Red indicates the X-axis, green indicates the Y-axis, and blue indicates the Z-axis</strong>.</p>", "a[href=\"operation_guide/shutdown.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.4 </span>Shutdown Guide<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">2.4.1 </span>Assist the Robot to Lie Down (No Gantry Required)<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Step 1: Enter Standing Preparation Mode (Position-Control Standing)<a class=\"headerlink\" href=\"#step-1\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"faq/temp_works.html#agent-only-voice\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8.1 </span>Disable the Built-in Interaction System and Use Your Own Voice System<a class=\"headerlink\" href=\"#agent-only-voice\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>By default, when the robot is powered on, it automatically enters natural voice interaction mode, and the interaction module occupies the audio input/output streams.</strong> If you need to integrate your own voice system and access the audio streams, you can temporarily disable the built-in interaction module using the steps below. <strong>Future versions will support one-click switching to secondary-development interaction mode to further simplify custom voice system integration.</strong></p>", "a[href=\"faq/temp_works.html#v0-7-xmcaction\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8.2 </span>Motion State Simplification: Some McAction state codes prior to v0.7.x are no longer supported<a class=\"headerlink\" href=\"#v0-7-xmcaction\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"about_agibot_X2/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1 </span><i class=\"fa-brands fa-bilibili\"></i> About AgiBot X2<a class=\"headerlink\" href=\"#agibot-x2\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"Interface/FASM/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.3 </span>Fault &amp; System Management Module (Coming Soon)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 SDK Fault &amp; System Management Module \u2013 Providing fault diagnostics and system management capabilities</strong></p><p>The Fault &amp; System Management module is a key component of the AgiBot X2 SDK, providing fault diagnostics and system-level management capabilities. Through these interfaces, developers can promptly detect and handle robot faults, manage permissions, monitor system status, and ensure safe and stable operation.</p>", "a[href=\"Interface/interactor/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.2 </span>Interaction Module<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>AgiBot X2 AimDK Interaction Module \u2013 providing rich human\u2013robot interaction interfaces</strong></p><p><strong>Core Features</strong></p>", "a[href=\"about_agibot_X2/part_name.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.1 </span>Product Overview<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">1.1.1 </span>X2 Ultra Edition<a class=\"headerlink\" href=\"#x2-ultra\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"about_agibot_X2/sensor_fov.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.6 </span>AgiBot X2 Sensor Overview<a class=\"headerlink\" href=\"#x2\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">1.6.1 </span>Sensor Capabilities &amp; FOV Diagram<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"quick_start/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4 </span><i class=\"fa fa-rocket\"></i> Quick Start<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>In this chapter, we demonstrate how to use <strong>AimDK</strong> for secondary development on the AgiBot X2 by walking through <strong>building and running SDK sample programs</strong> and <strong>developing combined robot control programs</strong>.</p>", "a[href=\"about_agibot_X2/joint_name_and_limit.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.7 </span>Joint Motion Range Description (Warranted)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">1.7.1 </span>Arm Motion Range<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"quick_start/prerequisites.html#id2\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.2 </span>Complete the basic system configuration<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h1><p>And SDK example dependencies:</p>", "a[href=\"quick_start/prerequisites.html#id3\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.3 </span>Network connection<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h1><p>The AgiBot X2 Ultra supports multiple network access methods to connect to the onboard system:</p><p><strong>(1) Direct wired connection via the rear Ethernet port</strong> \u2014 Connect a network cable between the robot\u2019s <a class=\"reference internal\" href=\"about_agibot_X2/SDK_interface.html#img-x2-sdk-interface\"><span class=\"std std-ref\">SDK development Ethernet port</span></a> and the host PC.</p>", "a[href=\"about_agibot_X2/robot_specifications.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.2 </span>Robot Specifications<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>The <strong>AgiBot X2 Series</strong> is equipped with a comprehensive set of <strong>hardware and system resources</strong>, including the <strong>mechanical structure</strong>, <strong>sensor systems</strong>, <strong>communication interfaces</strong>, <strong>computing units, and power systems</strong>. With this highly integrated architecture, the AgiBot X2 enables <strong>complex whole-body motion control</strong>, <strong>intelligent perception and environmental interaction</strong>, and supports <strong>advanced secondary development</strong> through <strong>AimDK</strong>.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
